// ============================================================================
// Kalta – P2P Sync screen
// Two-phase commit: both peers exchange bundles, each previews what would
// change locally, both must explicitly Accept before either side writes
// anything to its local DB. Either side can Reject to cancel the exchange.
//
// Hermes has a known HBC codegen bug where a static `module.member`
// reference inside a useCallback body can crash the screen on mount in
// release builds. We resolve the native module lazily via dynamic import
// so the reference isn't in the generated bytecode of any hook body.
// ============================================================================
import { useCallback, useEffect, useRef, useState } from 'react';
import {
  ActivityIndicator,
  Alert,
  FlatList,
  Pressable,
  StyleSheet,
  Text,
  View,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useRouter } from 'expo-router';
import * as Haptics from 'expo-haptics';
import { getActiveUser, getActiveUserId } from '@/src/lib/supabase';
import {
  decodeMessage,
  encodeMessage,
  exportSyncBundle,
  importSyncBundle,
  previewSyncBundle,
  resolutionKey,
  type P2PMessage,
  type P2PPreviewEntry,
  type P2PResolutions,
} from '@/src/lib/p2pSync';
import { colors, radius, spacing, typography } from '@/src/theme';
import { Icon } from '@/src/components/Icon';
import { ResourceIconWithOp, type ResourceTable } from '@/src/components/ResourceIcon';
import type { Category } from '@/src/types/database';

type Multipeer = typeof import('@/modules/kalta-multipeer/src');

let cachedMultipeer: Multipeer | null = null;
async function resolveMultipeer(): Promise<Multipeer> {
  if (!cachedMultipeer) {
    cachedMultipeer = await import('@/modules/kalta-multipeer/src');
  }
  return cachedMultipeer;
}

type Phase =
  | 'idle'
  | 'searching'
  | 'connecting'
  | 'connected'
  | 'exchanging'    // sent my bundle, waiting for peer's
  | 'reviewing'    // both bundles exchanged, user must accept/reject
  | 'waiting_peer' // I accepted, waiting for peer's decision
  | 'disagreed'    // both accepted but conflict picks differ
  | 'applying'     // both accepted, writing to local DB
  | 'done'
  | 'rejected'
  | 'error';

interface Peer {
  displayName: string;
}

type Decision = 'pending' | 'accept' | 'reject';

export default function P2PSyncScreen() {
  const router = useRouter();
  const [phase, setPhase] = useState<Phase>('idle');
  const [peers, setPeers] = useState<Peer[]>([]);
  const [connectedPeer, setConnectedPeer] = useState<string | null>(null);

  const [peerBundle, setPeerBundle] = useState<string | null>(null);
  const [peerSenderName, setPeerSenderName] = useState<string | null>(null);
  const [preview, setPreview] = useState<P2PPreviewEntry[]>([]);
  const [myDecision, setMyDecision] = useState<Decision>('pending');
  const [peerDecision, setPeerDecision] = useState<Decision>('pending');
  // Per-field resolutions for conflicts in this exchange. Defaults to
  // each peer's own local ("mine") value; the user can flip individual
  // fields to the peer's value before accepting. Both peers must end up
  // with the exact same map for the apply to proceed.
  const [myResolutions, setMyResolutions] = useState<P2PResolutions>({});

  const [syncResult, setSyncResult] = useState<{ inserted: number; updated: number; conflicts: number } | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [rejectedBy, setRejectedBy] = useState<'me' | 'peer' | null>(null);
  // Soft error surfaced on the waiting_peer screen — distinct from the
  // hard `phase = 'error'` because the connection is likely still alive
  // and the user can simply retry the send.
  const [sendError, setSendError] = useState<string | null>(null);
  // Delivery status for the most recent outbound message. Updated as
  // we send → wait for the peer's ACK → either confirm or time out.
  // Visible to the user as a pill so they always know whether their
  // last action actually made it across the wire.
  const [delivery, setDelivery] = useState<{
    state: 'idle' | 'sending' | 'delivered' | 'failed';
    label: string;
  }>({ state: 'idle', label: '' });
  const ackTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  // Connecting-phase watchdog. iOS sometimes silently stalls in the
  // MCSession `.connecting` state without ever firing the .connected or
  // .notConnected delegate. After ~15s we give up so the user can try
  // again instead of seeing an indefinite spinner.
  const connectTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const userIdRef = useRef<string | null>(null);
  const userNameRef = useRef<string | null>(null);
  // Refs let event listeners read the latest values without rebinding the
  // listener every render — the multipeer event subscription is set up
  // once on mount and stays until the screen unmounts.
  const myDecisionRef = useRef<Decision>('pending');
  const peerDecisionRef = useRef<Decision>('pending');
  const peerBundleRef = useRef<string | null>(null);
  const myResolutionsRef = useRef<P2PResolutions>({});
  const peerResolutionsRef = useRef<P2PResolutions | null>(null);
  // Whether we've already shipped our own BUNDLE in this exchange.
  // Drives auto-response: if peer's BUNDLE arrives and we haven't sent
  // ours, we ship one immediately so they're not stuck in exchanging.
  const myBundleSentRef = useRef<boolean>(false);

  useEffect(() => { myDecisionRef.current = myDecision; }, [myDecision]);
  useEffect(() => { peerDecisionRef.current = peerDecision; }, [peerDecision]);
  useEffect(() => { peerBundleRef.current = peerBundle; }, [peerBundle]);
  useEffect(() => { myResolutionsRef.current = myResolutions; }, [myResolutions]);

  useEffect(() => {
    getActiveUserId().then((uid) => { userIdRef.current = uid; });
    getActiveUser().then((u) => { userNameRef.current = u?.email ?? null; });
  }, []);

  // Clear any pending timers on unmount so we don't leak them.
  useEffect(() => {
    return () => {
      if (ackTimerRef.current) clearTimeout(ackTimerRef.current);
      if (connectTimerRef.current) clearTimeout(connectTimerRef.current);
    };
  }, []);

  // Reset the delivery indicator after a delivered status so the pill
  // doesn't linger on screen forever.
  useEffect(() => {
    if (delivery.state !== 'delivered') return;
    const t = setTimeout(() => setDelivery({ state: 'idle', label: '' }), 2_000);
    return () => clearTimeout(t);
  }, [delivery]);

  // Centralised send-with-ACK helper. Sets the delivery pill, ships the
  // message, then schedules a timeout that flips the pill to "failed"
  // if the peer doesn't echo back within 4s. The matching ACK handler
  // (in `handleIncomingMessage`) clears the timer and sets "delivered".
  const sendWithAck = useCallback(
    async (msg: P2PMessage, label: string): Promise<boolean> => {
      if (ackTimerRef.current) {
        clearTimeout(ackTimerRef.current);
        ackTimerRef.current = null;
      }
      setSendError(null);
      setDelivery({ state: 'sending', label: `Sending ${label}…` });
      const wire = encodeMessage(msg);
      console.log('[p2p] →', msg.type, 'bytes=', wire.length);
      try {
        const mp = await resolveMultipeer();
        await mp.sendData(wire);
      } catch (e: any) {
        const err = e?.message ?? 'Send failed';
        console.warn('[p2p] send failed:', err);
        setDelivery({ state: 'failed', label: `${label}: ${err}` });
        setSendError(err);
        return false;
      }
      ackTimerRef.current = setTimeout(() => {
        // Peer never confirmed — likely silent MCSession drop.
        console.warn('[p2p] ACK timeout for', msg.type);
        setDelivery({
          state: 'failed',
          label: `${label} not delivered — try Resend`,
        });
        setSendError('Peer did not confirm receipt');
      }, 4_000);
      return true;
    },
    [],
  );

  // Reset all sync-state when starting a fresh exchange.
  const resetExchangeState = useCallback(() => {
    setPeerBundle(null);
    setPeerSenderName(null);
    setPreview([]);
    setMyDecision('pending');
    setPeerDecision('pending');
    setMyResolutions({});
    peerResolutionsRef.current = null;
    myBundleSentRef.current = false;
    setSyncResult(null);
    setRejectedBy(null);
    setSendError(null);
  }, []);

  const handleStart = useCallback(async () => {
    try {
      const user = await getActiveUser();
      const rawName = user?.email?.trim() || 'Kalta User';
      const displayName = rawName.length > 30 ? rawName.slice(0, 30) : rawName;
      userIdRef.current = user?.id ?? null;
      userNameRef.current = user?.email ?? null;

      const mp = await resolveMultipeer();
      await mp.startSession(displayName);
      setPhase('searching');
      setPeers([]);
      setConnectedPeer(null);
      resetExchangeState();
      setErrorMsg(null);
    } catch (e: any) {
      setErrorMsg(e?.message ?? String(e) ?? 'Failed to start');
      setPhase('error');
    }
  }, [resetExchangeState]);

  // Apply the peer's bundle locally and finish. Both peers reach this
  // point only after exchanging matching resolution maps, so the import
  // is deterministic and converges both devices to the same state.
  const applyPeerBundle = useCallback(() => {
    const bundle = peerBundleRef.current;
    if (!bundle) return;
    setPhase('applying');
    try {
      const result = importSyncBundle(bundle, myResolutionsRef.current);
      setSyncResult({
        inserted: result.inserted,
        updated: result.updated,
        conflicts: result.conflicts,
      });
      setPhase('done');
      Haptics.notificationAsync(
        result.conflicts > 0
          ? Haptics.NotificationFeedbackType.Warning
          : Haptics.NotificationFeedbackType.Success,
      ).catch(() => {});
    } catch (err: any) {
      setErrorMsg(err?.message ?? 'Apply failed');
      setPhase('error');
    }
  }, []);

  useEffect(() => {
    let subs: { remove: () => void }[] = [];
    let cancelled = false;

    (async () => {
      const mp = await resolveMultipeer();
      if (cancelled) return;

      subs = [
        mp.onPeerFound((e) => {
          setPeers((prev) => {
            if (prev.some((p) => p.displayName === e.peerDisplayName)) return prev;
            return [...prev, { displayName: e.peerDisplayName }];
          });
        }),
        mp.onPeerLost((e) => {
          setPeers((prev) => prev.filter((p) => p.displayName !== e.peerDisplayName));
        }),
        mp.onConnecting((e) => {
          setPhase('connecting');
          setConnectedPeer(e.peerDisplayName);
          // Arm the watchdog — if we're still connecting after the
          // timeout, drop the attempt so the user can re-tap the peer.
          if (connectTimerRef.current) clearTimeout(connectTimerRef.current);
          connectTimerRef.current = setTimeout(() => {
            console.warn('[p2p] connect timed out, returning to searching');
            resolveMultipeer().then((mp2) => mp2.stopSession()).catch(() => {});
            // stopSession kills advertiser/browser; restart so the peer
            // list repopulates and the user can try again immediately.
            setTimeout(() => {
              const u = userNameRef.current?.trim() || 'Kalta User';
              const dn = u.length > 30 ? u.slice(0, 30) : u;
              resolveMultipeer().then((mp2) => mp2.startSession(dn)).catch(() => {});
            }, 500);
            setPeers([]);
            setConnectedPeer(null);
            resetExchangeState();
            setPhase('searching');
          }, 15_000);
        }),
        mp.onConnected((e) => {
          if (connectTimerRef.current) {
            clearTimeout(connectTimerRef.current);
            connectTimerRef.current = null;
          }
          setPhase('connected');
          setConnectedPeer(e.peerDisplayName);
          Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success).catch(() => {});
        }),
        mp.onDisconnected(() => {
          if (connectTimerRef.current) {
            clearTimeout(connectTimerRef.current);
            connectTimerRef.current = null;
          }
          // If we're mid-exchange and peer drops, treat as reject.
          if (phaseAllowsCancel()) {
            setRejectedBy('peer');
            setPhase('rejected');
          } else {
            setPhase('searching');
            setConnectedPeer(null);
            resetExchangeState();
          }
        }),
        mp.onDataReceived((e) => {
          const msg = decodeMessage(e.data);
          if (!msg) {
            setErrorMsg('Received malformed P2P message');
            setPhase('error');
            return;
          }
          handleIncomingMessage(msg);
        }),
        mp.onError((e) => {
          setErrorMsg(e.message);
          setPhase('error');
        }),
      ];
    })();

    return () => {
      cancelled = true;
      subs.forEach((s) => s.remove());
    };
    // We intentionally bind once on mount — the listeners read latest state
    // via refs and setState calls.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Handle a P2P message that just arrived from the peer.
  const handleIncomingMessage = useCallback((msg: P2PMessage) => {
    console.log(
      '[p2p] ←',
      msg.type,
      msg.type === 'ACCEPT'
        ? `(resolutions=${Object.keys(msg.resolutions ?? {}).length})`
        : msg.type === 'ACK'
        ? `(ackOf=${msg.ackOf})`
        : '',
    );

    // ACKs only update the delivery pill — they're the receipt for one
    // of our outbound messages, never a state change in the protocol.
    if (msg.type === 'ACK') {
      if (ackTimerRef.current) {
        clearTimeout(ackTimerRef.current);
        ackTimerRef.current = null;
      }
      setDelivery({ state: 'delivered', label: `${msg.ackOf} delivered` });
      return;
    }

    // Echo back an ACK immediately so the sender knows we received it.
    // Fire-and-forget — if our ACK is lost the sender will see the
    // timeout and can resend; we don't want to gate state transitions
    // on a successful ACK send.
    resolveMultipeer()
      .then((mp) => mp.sendData(encodeMessage({ type: 'ACK', ackOf: msg.type })))
      .catch(() => {});

    if (msg.type === 'BUNDLE') {
      // Peer sent their bundle. Compute preview and move to review.
      // Pre-populate `myResolutions` with each conflict's local value so
      // the picker has a sensible default — accepting without changing
      // anything keeps the user's own edits.
      const bundle = msg.bundle;
      try {
        const computed = previewSyncBundle(bundle);
        const defaults: P2PResolutions = {};
        for (const e of computed) {
          for (const f of e.conflict_fields) {
            const key = resolutionKey(e.table_name, e.row_id, f);
            defaults[key] = e.before_values?.[f] ?? null;
          }
        }
        setPeerBundle(bundle);
        setPeerSenderName(msg.senderName ?? null);
        setPreview(computed);
        setMyResolutions(defaults);
        setPhase('reviewing');

        // Auto-respond with our own bundle if the peer initiated and
        // we haven't sent ours yet. Without this the initiator stays
        // parked on "exchanging…" forever because they're waiting for
        // a bundle from us that we never send.
        if (!myBundleSentRef.current && userIdRef.current) {
          myBundleSentRef.current = true;
          const myBundle = exportSyncBundle(userIdRef.current);
          console.log('[p2p] auto-responding with my BUNDLE');
          resolveMultipeer()
            .then((mp) =>
              mp.sendData(
                encodeMessage({
                  type: 'BUNDLE',
                  bundle: myBundle,
                  senderName: userNameRef.current ?? undefined,
                }),
              ),
            )
            .catch((e) => {
              console.warn('[p2p] auto-bundle send failed:', e?.message);
              setSendError(e?.message ?? 'Could not send my bundle to peer');
            });
        }
      } catch (err: any) {
        setErrorMsg(err?.message ?? 'Could not parse peer bundle');
        setPhase('error');
      }
      return;
    }

    if (msg.type === 'ACCEPT') {
      setPeerDecision('accept');
      peerResolutionsRef.current = msg.resolutions ?? {};
      // If I'm already accepted, compare resolutions. Both peers must
      // have made the same picks for each conflict before we apply.
      if (myDecisionRef.current === 'accept') {
        if (resolutionsAgree(myResolutionsRef.current, peerResolutionsRef.current)) {
          applyPeerBundle();
        } else {
          setPhase('disagreed');
        }
      }
      return;
    }

    if (msg.type === 'REJECT') {
      setPeerDecision('reject');
      setRejectedBy('peer');
      setPhase('rejected');
      return;
    }
  }, [applyPeerBundle]);

  const handleConnect = useCallback(async (peer: Peer) => {
    try {
      const mp = await resolveMultipeer();
      await mp.invitePeer(peer.displayName);
      setPhase('connecting');
      setConnectedPeer(peer.displayName);
    } catch (e: any) {
      Alert.alert('Connection failed', e?.message ?? 'Unknown error');
    }
  }, []);

  // User taps "Sync now" — we send our bundle. Either side can initiate;
  // the other side auto-responds when the BUNDLE arrives, so the user
  // who didn't tap doesn't have to.
  const handleStartSync = useCallback(async () => {
    if (!userIdRef.current) return;
    resetExchangeState();
    const bundle = exportSyncBundle(userIdRef.current);
    myBundleSentRef.current = true;
    const ok = await sendWithAck(
      { type: 'BUNDLE', bundle, senderName: userNameRef.current ?? undefined },
      'data',
    );
    // Move to next phase regardless of ACK status — the delivery pill
    // surfaces failure independently and we don't want to block on the
    // ACK round-trip.
    if (peerBundleRef.current) {
      setPhase('reviewing');
    } else {
      setPhase('exchanging');
    }
    if (!ok) {
      // delivery pill already shows failure
      return;
    }
  }, [resetExchangeState, sendWithAck]);

  const handleAccept = useCallback(async () => {
    setMyDecision('accept');
    const resolutions = myResolutionsRef.current;
    const ok = await sendWithAck({ type: 'ACCEPT', resolutions }, 'decision');
    Haptics.selectionAsync().catch(() => {});
    if (!ok) {
      // sendWithAck already surfaced the failure on the delivery pill
      // and populated sendError. Park on waiting_peer so the user can
      // hit Resend (or wait for the ACK timeout).
      setPhase('waiting_peer');
      return;
    }
    if (peerDecisionRef.current === 'accept' && peerResolutionsRef.current !== null) {
      if (resolutionsAgree(resolutions, peerResolutionsRef.current)) {
        applyPeerBundle();
      } else {
        setPhase('disagreed');
      }
    } else {
      setPhase('waiting_peer');
    }
  }, [applyPeerBundle, sendWithAck]);

  // Re-send my ACCEPT to the peer. Reachable from the waiting_peer
  // screen when the user suspects the first send didn't make it.
  const handleResendAccept = useCallback(async () => {
    const resolutions = myResolutionsRef.current;
    await sendWithAck({ type: 'ACCEPT', resolutions }, 'decision');
  }, [sendWithAck]);

  // User picks "Mine" / "Theirs" for a single conflict field.
  const handlePickResolution = useCallback((key: string, value: unknown) => {
    setMyResolutions((prev) => ({ ...prev, [key]: value }));
    Haptics.selectionAsync().catch(() => {});
  }, []);

  // After a disagreement, both peers reset their decision and re-enter
  // reviewing so they can adjust picks. The peer reaches the same state
  // independently because the comparison is deterministic.
  const handleAdjustPicks = useCallback(() => {
    setMyDecision('pending');
    setPeerDecision('pending');
    peerResolutionsRef.current = null;
    setPhase('reviewing');
  }, []);

  const handleReject = useCallback(async () => {
    setMyDecision('reject');
    setRejectedBy('me');
    await sendWithAck({ type: 'REJECT' }, 'reject');
    Haptics.notificationAsync(Haptics.NotificationFeedbackType.Warning).catch(() => {});
    setPhase('rejected');
  }, [sendWithAck]);

  const handleRetry = useCallback(() => {
    resetExchangeState();
    setPhase('connected');
  }, [resetExchangeState]);

  // Clean up the session on unmount.
  useEffect(() => {
    return () => {
      resolveMultipeer().then((mp) => mp.stopSession()).catch(() => {});
    };
  }, []);

  const handleDone = useCallback(() => {
    resolveMultipeer().then((mp) => mp.stopSession()).catch(() => {});
    router.back();
  }, [router]);

  const handleBack = useCallback(() => {
    resolveMultipeer().then((mp) => mp.stopSession()).catch(() => {});
    router.back();
  }, [router]);

  const peerLabel = peerSenderName ?? connectedPeer ?? 'peer';

  // Show the persistent status strip whenever we're past the initial
  // device picker — the user always wants to see if the connection is
  // alive and whether their last message actually got through.
  const showStatusStrip = ['connected', 'exchanging', 'reviewing', 'waiting_peer', 'disagreed'].includes(
    phase,
  );

  return (
    <SafeAreaView style={styles.container} edges={['top', 'bottom']}>
      <View style={styles.topBar}>
        <Pressable
          hitSlop={12}
          onPress={handleBack}
          style={({ pressed }) => [styles.topBarBtn, pressed && { opacity: 0.5 }]}
        >
          <Icon sf="chevron.left" size={22} color={colors.text} />
        </Pressable>
        <Text style={styles.topBarTitle}>P2P Sync</Text>
        <View style={styles.topBarBtn} />
      </View>

      {showStatusStrip && (
        <View style={styles.statusStrip}>
          <View style={styles.statusItem}>
            <View
              style={[
                styles.statusDot,
                { backgroundColor: connectedPeer ? colors.success : colors.warningText },
              ]}
            />
            <Text style={styles.statusText} numberOfLines={1}>
              {connectedPeer ? `Connected · ${peerLabel}` : 'Disconnected'}
            </Text>
          </View>
          {delivery.state !== 'idle' && (
            <View
              style={[
                styles.deliveryPill,
                delivery.state === 'sending' && styles.deliveryPillSending,
                delivery.state === 'delivered' && styles.deliveryPillOk,
                delivery.state === 'failed' && styles.deliveryPillFail,
              ]}
            >
              {delivery.state === 'sending' && (
                <ActivityIndicator size="small" color={colors.text} />
              )}
              {delivery.state === 'delivered' && (
                <Icon sf="checkmark.circle.fill" size={12} color={colors.successText} />
              )}
              {delivery.state === 'failed' && (
                <Icon sf="exclamationmark.circle.fill" size={12} color={colors.warningText} />
              )}
              <Text style={styles.deliveryText} numberOfLines={1}>
                {delivery.label}
              </Text>
            </View>
          )}
        </View>
      )}

      {phase === 'idle' && (
        <View style={styles.center}>
          <Icon sf="antenna.radiowaves.left.and.right" size={64} color={colors.primary} />
          <Text style={styles.headline}>Sync with nearby iPhone</Text>
          <Text style={styles.description}>
            Uses Bluetooth and WiFi to exchange data directly with another Kalta device. No
            internet needed.
          </Text>
          <Pressable
            style={({ pressed }) => [styles.primaryBtn, pressed && { opacity: 0.8 }]}
            onPress={handleStart}
          >
            <Icon sf="magnifyingglass" size={18} color={colors.textOnPrimary} />
            <Text style={styles.primaryBtnText}>Start searching</Text>
          </Pressable>
        </View>
      )}

      {phase === 'searching' && (
        <View style={styles.searchSection}>
          <View style={styles.searchingHeader}>
            <ActivityIndicator color={colors.primary} />
            <Text style={styles.searchingText}>Searching for nearby devices...</Text>
          </View>
          <Text style={styles.hint}>
            Make sure the other device also has Kalta open on this screen.
          </Text>
          {peers.length > 0 && (
            <View style={styles.peerList}>
              <Text style={styles.sectionLabel}>DEVICES FOUND</Text>
              {peers.map((peer) => (
                <Pressable
                  key={peer.displayName}
                  style={({ pressed }) => [styles.peerRow, pressed && { opacity: 0.7 }]}
                  onPress={() => handleConnect(peer)}
                >
                  <Icon sf="iphone" size={24} color={colors.primary} />
                  <View style={styles.peerInfo}>
                    <Text style={styles.peerName}>{peer.displayName}</Text>
                    <Text style={styles.peerHint}>Tap to connect</Text>
                  </View>
                  <Icon sf="arrow.right.circle.fill" size={24} color={colors.primary} />
                </Pressable>
              ))}
            </View>
          )}
        </View>
      )}

      {phase === 'connecting' && (
        <View style={styles.center}>
          <ActivityIndicator size="large" color={colors.primary} />
          <Text style={styles.headline}>Connecting...</Text>
          <Text style={styles.description}>Establishing secure connection with {peerLabel}</Text>
        </View>
      )}

      {phase === 'connected' && (
        <View style={styles.center}>
          <Icon sf="checkmark.circle.fill" size={64} color={colors.success} />
          <Text style={styles.headline}>Connected</Text>
          <Text style={styles.description}>
            Connected to {peerLabel}. Tap sync to exchange data — both of you will be able to
            review the proposed changes before anything is saved.
          </Text>
          <Pressable
            style={({ pressed }) => [styles.primaryBtn, pressed && { opacity: 0.8 }]}
            onPress={handleStartSync}
          >
            <Icon sf="arrow.triangle.2.circlepath" size={18} color={colors.textOnPrimary} />
            <Text style={styles.primaryBtnText}>Sync now</Text>
          </Pressable>
        </View>
      )}

      {phase === 'exchanging' && (
        <View style={styles.center}>
          <ActivityIndicator size="large" color={colors.primary} />
          <Text style={styles.headline}>Exchanging data...</Text>
          <Text style={styles.description}>
            Waiting for {peerLabel} to send their changes.
          </Text>
        </View>
      )}

      {phase === 'reviewing' && (
        <ReviewList
          peerLabel={peerLabel}
          preview={preview}
          onAccept={handleAccept}
          onReject={handleReject}
          peerDecision={peerDecision}
          resolutions={myResolutions}
          onPickResolution={handlePickResolution}
        />
      )}

      {phase === 'waiting_peer' && (
        <View style={styles.center}>
          {sendError ? (
            <Icon sf="exclamationmark.triangle.fill" size={48} color={colors.warningText} />
          ) : (
            <ActivityIndicator size="large" color={colors.primary} />
          )}
          <Text style={styles.headline}>
            {sendError ? 'Could not reach peer' : `Waiting for ${peerLabel}…`}
          </Text>
          <Text style={styles.description}>
            {sendError
              ? `Send failed: ${sendError}. Tap below to try again.`
              : `You accepted. ${peerLabel} still needs to confirm before changes apply on either device. If they say nothing changed on their side, tap Resend.`}
          </Text>
          <Pressable
            style={({ pressed }) => [styles.primaryBtn, pressed && { opacity: 0.8 }]}
            onPress={handleResendAccept}
          >
            <Icon sf="paperplane.fill" size={16} color={colors.textOnPrimary} />
            <Text style={styles.primaryBtnText}>Resend my decision</Text>
          </Pressable>
          <Pressable
            style={({ pressed }) => [styles.secondaryBtn, pressed && { opacity: 0.6 }]}
            onPress={handleReject}
          >
            <Text style={styles.secondaryBtnText}>Cancel</Text>
          </Pressable>
        </View>
      )}

      {phase === 'disagreed' && (
        <View style={styles.center}>
          <Icon sf="exclamationmark.triangle.fill" size={64} color={colors.warningText} />
          <Text style={styles.headline}>Picks don't match</Text>
          <Text style={styles.description}>
            You and {peerLabel} chose different values for one or more conflicts. Both devices
            need to land on the same picks before applying.
          </Text>
          <Pressable
            style={({ pressed }) => [styles.primaryBtn, pressed && { opacity: 0.8 }]}
            onPress={handleAdjustPicks}
          >
            <Icon sf="arrow.triangle.2.circlepath" size={18} color={colors.textOnPrimary} />
            <Text style={styles.primaryBtnText}>Adjust picks</Text>
          </Pressable>
          <Pressable
            style={({ pressed }) => [styles.secondaryBtn, pressed && { opacity: 0.6 }]}
            onPress={handleReject}
          >
            <Text style={styles.secondaryBtnText}>Cancel sync</Text>
          </Pressable>
        </View>
      )}

      {phase === 'applying' && (
        <View style={styles.center}>
          <ActivityIndicator size="large" color={colors.primary} />
          <Text style={styles.headline}>Applying changes…</Text>
        </View>
      )}

      {phase === 'done' && (
        <View style={styles.center}>
          <Icon
            sf={syncResult && syncResult.conflicts > 0 ? 'exclamationmark.triangle.fill' : 'checkmark.circle.fill'}
            size={64}
            color={syncResult && syncResult.conflicts > 0 ? colors.warningText : colors.success}
          />
          <Text style={styles.headline}>Sync complete</Text>
          {syncResult && (
            <Text style={styles.description}>
              {syncResult.inserted} new, {syncResult.updated} updated
              {syncResult.conflicts > 0 ? `, ${syncResult.conflicts} need your attention` : '.'}
            </Text>
          )}
          {syncResult && syncResult.conflicts > 0 && (
            <Pressable
              style={({ pressed }) => [styles.primaryBtn, pressed && { opacity: 0.8 }]}
              onPress={() => {
                resolveMultipeer().then((mp) => mp.stopSession()).catch(() => {});
                router.push('/conflicts' as any);
              }}
            >
              <Icon sf="arrow.up.right.square" size={18} color={colors.textOnPrimary} />
              <Text style={styles.primaryBtnText}>Resolve conflicts</Text>
            </Pressable>
          )}
          <Pressable
            style={({ pressed }) => [
              syncResult && syncResult.conflicts > 0 ? styles.secondaryBtn : styles.primaryBtn,
              pressed && { opacity: 0.8 },
            ]}
            onPress={handleDone}
          >
            <Text
              style={
                syncResult && syncResult.conflicts > 0
                  ? styles.secondaryBtnText
                  : styles.primaryBtnText
              }
            >
              Done
            </Text>
          </Pressable>
        </View>
      )}

      {phase === 'rejected' && (
        <View style={styles.center}>
          <Icon sf="xmark.circle.fill" size={64} color={colors.warningText} />
          <Text style={styles.headline}>Sync canceled</Text>
          <Text style={styles.description}>
            {rejectedBy === 'me'
              ? `You rejected the changes from ${peerLabel}. Nothing was saved.`
              : `${peerLabel} canceled the sync. Nothing was saved.`}
          </Text>
          <Pressable
            style={({ pressed }) => [styles.primaryBtn, pressed && { opacity: 0.8 }]}
            onPress={handleRetry}
          >
            <Icon sf="arrow.triangle.2.circlepath" size={18} color={colors.textOnPrimary} />
            <Text style={styles.primaryBtnText}>Try again</Text>
          </Pressable>
          <Pressable
            style={({ pressed }) => [styles.secondaryBtn, pressed && { opacity: 0.6 }]}
            onPress={handleDone}
          >
            <Text style={styles.secondaryBtnText}>Done</Text>
          </Pressable>
        </View>
      )}

      {phase === 'error' && (
        <View style={styles.center}>
          <Icon sf="exclamationmark.triangle.fill" size={64} color={colors.warningText} />
          <Text style={styles.headline}>Something went wrong</Text>
          <Text style={styles.description}>{errorMsg}</Text>
          <Pressable
            style={({ pressed }) => [styles.primaryBtn, pressed && { opacity: 0.8 }]}
            onPress={handleStart}
          >
            <Text style={styles.primaryBtnText}>Try again</Text>
          </Pressable>
        </View>
      )}
    </SafeAreaView>
  );

  // Phases during which a disconnect should cancel the in-flight exchange
  // rather than just bouncing back to the searching screen.
  function phaseAllowsCancel() {
    return ['exchanging', 'reviewing', 'waiting_peer'].includes(phase);
  }
}

// ----------------------------------------------------------------------------
// Review list — renders the proposed changes from the peer's bundle.
// ----------------------------------------------------------------------------

// Compare two resolution maps for full agreement. We require identical
// key sets and identical values per key — anything missing on one side
// or differing in value blocks the apply and routes both peers to the
// "disagreed" screen so they can adjust before retrying.
function resolutionsAgree(a: P2PResolutions, b: P2PResolutions): boolean {
  const keys = new Set([...Object.keys(a), ...Object.keys(b)]);
  for (const k of keys) {
    if (!(k in a) || !(k in b)) return false;
    const av = a[k];
    const bv = b[k];
    if (av === bv) continue;
    if (av == null && bv == null) continue;
    if (String(av ?? '') === String(bv ?? '')) continue;
    return false;
  }
  return true;
}

function isResolutionValueEqual(a: unknown, b: unknown): boolean {
  if (a === b) return true;
  if (a == null && b == null) return true;
  return String(a ?? '') === String(b ?? '');
}

function ReviewList({
  peerLabel,
  preview,
  onAccept,
  onReject,
  peerDecision,
  resolutions,
  onPickResolution,
}: {
  peerLabel: string;
  preview: P2PPreviewEntry[];
  onAccept: () => void;
  onReject: () => void;
  peerDecision: Decision;
  resolutions: P2PResolutions;
  onPickResolution: (key: string, value: unknown) => void;
}) {
  const conflictCount = preview.reduce((n, e) => n + e.conflict_fields.length, 0);
  const insertCount = preview.filter((e) => e.operation === 'INSERT').length;
  const updateCount = preview.filter((e) => e.operation === 'UPDATE').length;

  return (
    <View style={styles.reviewContainer}>
      <View style={styles.reviewBanner}>
        <Icon sf="person.2.fill" size={18} color={colors.warningText} />
        <View style={{ flex: 1 }}>
          <Text style={styles.reviewBannerTitle}>Changes from {peerLabel}</Text>
          <Text style={styles.reviewBannerSubtitle}>
            {preview.length === 0
              ? 'No incoming changes — nothing to apply on this device.'
              : `${insertCount} new, ${updateCount} updates${conflictCount > 0 ? `, ${conflictCount} conflicts` : ''}`}
          </Text>
        </View>
      </View>

      {peerDecision === 'accept' && (
        <View style={styles.peerStatusBar}>
          <Icon sf="checkmark.circle.fill" size={14} color={colors.success} />
          <Text style={styles.peerStatusText}>{peerLabel} already accepted</Text>
        </View>
      )}

      {preview.length === 0 ? (
        <View style={styles.center}>
          <Text style={styles.description}>
            Tap Accept to confirm — once {peerLabel} accepts as well, both devices stay in sync.
          </Text>
        </View>
      ) : (
        <FlatList
          data={preview}
          keyExtractor={(p) => `${p.table_name}:${p.row_id}`}
          contentContainerStyle={styles.reviewList}
          renderItem={({ item }) => (
            <ReviewCard
              entry={item}
              resolutions={resolutions}
              onPickResolution={onPickResolution}
            />
          )}
        />
      )}
      {conflictCount > 0 && (
        <Text style={styles.conflictHint}>
          Pick a value for each ⚠︎ conflict — both you and {peerLabel} must land on the same
          choice for the sync to apply.
        </Text>
      )}

      <View style={styles.actionBar}>
        <Pressable
          style={({ pressed }) => [styles.rejectBtn, pressed && { opacity: 0.8 }]}
          onPress={onReject}
        >
          <Icon sf="xmark" size={16} color={colors.warningText} />
          <Text style={styles.rejectBtnText}>Reject</Text>
        </Pressable>
        <Pressable
          style={({ pressed }) => [styles.acceptBtn, pressed && { opacity: 0.85 }]}
          onPress={onAccept}
        >
          <Icon sf="checkmark" size={16} color={colors.textOnPrimary} />
          <Text style={styles.acceptBtnText}>Accept</Text>
        </Pressable>
      </View>
    </View>
  );
}

const FIELD_LABELS: Record<string, string> = {
  name: 'Name',
  quantity: 'Quantity',
  unit: 'Unit',
  expiry_date: 'Expiry',
  barcode: 'Barcode',
  image_url: 'Photo',
  category: 'Category',
  notes: 'Notes',
  opened: 'Opened',
  damaged: 'Damaged',
  pack_count: 'Pack count',
  last_verified: 'Last verified',
  box_id: 'Box',
  location: 'Location',
  typical_expiry_days: 'Typical shelf life',
  completed_at: 'Completed',
  found_count: 'Found',
  missing_count: 'Missing',
};

function prettyField(field: string): string {
  return FIELD_LABELS[field] ?? field;
}

function formatValue(field: string, value: unknown): string {
  if (value === null || value === undefined || value === '') return '—';
  if (typeof value === 'boolean') return value ? 'Yes' : 'No';
  if (field === 'image_url') return 'updated';
  if (field === 'expiry_date' || field === 'last_verified' || field === 'completed_at') {
    const ts = String(value);
    if (ts === '9999-12-31') return 'Never';
    return ts.split('T')[0]?.split(' ')[0] ?? ts;
  }
  if (typeof value === 'number') {
    return Number.isInteger(value) ? String(value) : value.toFixed(2).replace(/\.?0+$/, '');
  }
  return String(value);
}

// formatValue plus context from sibling fields on the same side. Today
// only quantity carries this — its unit is meaningless on its own and
// the user shouldn't have to mentally pair "MINE 15" with the separate
// unit row to know it's "15 g". Same for the picker selection text.
function formatValueWithContext(
  field: string,
  value: unknown,
  sideValues: Record<string, any> | null | undefined,
): string {
  const base = formatValue(field, value);
  if (base === '—') return base;
  if (field === 'quantity' && sideValues) {
    const unit = sideValues.unit;
    if (unit) return `${base} ${unit}`;
  }
  return base;
}

function ReviewCard({
  entry,
  resolutions,
  onPickResolution,
}: {
  entry: P2PPreviewEntry;
  resolutions: P2PResolutions;
  onPickResolution: (key: string, value: unknown) => void;
}) {
  const fields = entry.changed_fields ?? [];
  const valueChanged = (f: string) => {
    if (!entry.before_values || !entry.after_values) return true;
    return formatValue(f, entry.before_values[f]) !== formatValue(f, entry.after_values[f]);
  };
  // Coupled rendering: when both quantity AND unit are in conflict for
  // an item, the quantity picker already prints "{q} {u}" via context, so
  // the separate unit picker would just duplicate it. Hide unit's row;
  // the quantity picker's onPress sets both resolutions atomically.
  const isCoupledItem =
    entry.table_name === 'items' &&
    entry.conflict_fields.includes('quantity') &&
    entry.conflict_fields.includes('unit');

  const visible = fields.filter((f) => {
    if (isCoupledItem && f === 'unit') return false;
    return valueChanged(f);
  });
  const isDelete = entry.operation === 'DELETE';
  const isInsert = entry.operation === 'INSERT';

  return (
    <View style={styles.reviewCard}>
      <ResourceIconWithOp
        table={entry.table_name as ResourceTable}
        category={(entry.category ?? null) as Category | null}
        operation={entry.operation}
        size={36}
      />
      <View style={styles.reviewCardBody}>
        <Text style={styles.reviewCardTitle} numberOfLines={1}>
          {entry.display_name}
        </Text>
        {entry.context && (
          <Text style={styles.reviewCardContext} numberOfLines={1}>
            {entry.context}
          </Text>
        )}
        {entry.conflict_fields.length > 0 && (
          <View style={styles.conflictBadge}>
            <Icon sf="exclamationmark.triangle.fill" size={10} color={colors.warningText} />
            <Text style={styles.conflictBadgeText}>
              {entry.conflict_fields.length} conflict{entry.conflict_fields.length > 1 ? 's' : ''}
            </Text>
          </View>
        )}
        {isDelete && (
          <Text style={styles.reviewDeleteHint}>
            Will be removed from this device too if you accept.
          </Text>
        )}
        {isInsert && (
          <Text style={styles.reviewInsertHint}>
            New on this device.
          </Text>
        )}

        {visible.length > 0 && (
          <View style={styles.diff}>
            {visible.map((f) => {
              const before = entry.before_values?.[f];
              const after = entry.after_values?.[f];
              const isConflict = entry.conflict_fields.includes(f);

              if (isConflict) {
                const key = resolutionKey(entry.table_name, entry.row_id, f);
                const chosen = key in resolutions ? resolutions[key] : before;
                const mineSelected = isResolutionValueEqual(chosen, before);
                const theirsSelected = isResolutionValueEqual(chosen, after);
                // For the coupled quantity field, picking also sets the
                // unit resolution to the same side so the two stay in
                // lockstep — and our resolution map matches the peer's.
                const pickMine = () => {
                  onPickResolution(key, before);
                  if (isCoupledItem && f === 'quantity') {
                    onPickResolution(
                      resolutionKey(entry.table_name, entry.row_id, 'unit'),
                      entry.before_values?.unit ?? null,
                    );
                  }
                };
                const pickTheirs = () => {
                  onPickResolution(key, after);
                  if (isCoupledItem && f === 'quantity') {
                    onPickResolution(
                      resolutionKey(entry.table_name, entry.row_id, 'unit'),
                      entry.after_values?.unit ?? null,
                    );
                  }
                };
                return (
                  <View key={f} style={styles.diffField}>
                    <Text style={[styles.diffFieldLabel, { color: colors.warningText }]}>
                      {prettyField(f)} ⚠︎
                    </Text>
                    <Pressable
                      onPress={pickMine}
                      style={({ pressed }) => [
                        styles.pickRow,
                        styles.pickMine,
                        mineSelected && styles.pickRowSelectedMine,
                        pressed && { opacity: 0.7 },
                      ]}
                    >
                      <Icon
                        sf={mineSelected ? 'largecircle.fill.circle' : 'circle'}
                        size={16}
                        color={mineSelected ? colors.dangerText : colors.textSubtle}
                      />
                      <View style={styles.pickContent}>
                        <Text style={styles.pickLabel}>MINE</Text>
                        <Text style={styles.pickValue} numberOfLines={2}>
                          {formatValueWithContext(f, before, entry.before_values)}
                        </Text>
                      </View>
                    </Pressable>
                    <Pressable
                      onPress={pickTheirs}
                      style={({ pressed }) => [
                        styles.pickRow,
                        styles.pickTheirs,
                        theirsSelected && styles.pickRowSelectedTheirs,
                        pressed && { opacity: 0.7 },
                      ]}
                    >
                      <Icon
                        sf={theirsSelected ? 'largecircle.fill.circle' : 'circle'}
                        size={16}
                        color={theirsSelected ? colors.successText : colors.textSubtle}
                      />
                      <View style={styles.pickContent}>
                        <Text style={styles.pickLabel}>THEIRS</Text>
                        <Text style={styles.pickValue} numberOfLines={2}>
                          {formatValueWithContext(f, after, entry.after_values)}
                        </Text>
                      </View>
                    </Pressable>
                  </View>
                );
              }

              return (
                <View key={f} style={styles.diffField}>
                  <Text style={styles.diffFieldLabel}>{prettyField(f)}</Text>
                  {entry.before_values && (
                    <View style={styles.diffMinus}>
                      <Text style={styles.diffMinusSign}>−</Text>
                      <Text style={styles.diffMinusText} numberOfLines={2}>
                        {formatValueWithContext(f, before, entry.before_values)}
                      </Text>
                    </View>
                  )}
                  <View style={styles.diffPlus}>
                    <Text style={styles.diffPlusSign}>+</Text>
                    <Text style={styles.diffPlusText} numberOfLines={2}>
                      {formatValueWithContext(f, after, entry.after_values)}
                    </Text>
                  </View>
                </View>
              );
            })}
          </View>
        )}
      </View>
    </View>
  );
}

